mepc_setup:       
                  la x6, init
                  csrw 0x341, x6

custom_csr_setup: 
                  csrwi 0x7c0, 1

init_user_mode:   
                  li x6, 0x0
                  csrw 0x300, x6 # MSTATUS
                  li x6, 0x0
                  csrw 0x304, x6 # MIE
                  li x20, 0x8ffffffc
